def normalize_cmd(cmd: tuple[str, ...]) -> tuple[str, ...]:
    """
    Fixes for the following issues on windows
    - https://bugs.python.org/issue8557
    - windows does not parse shebangs

    This function also makes deep-path shebangs work just fine
    """
    import os
    import sys

    if sys.platform == "win32":
        # Normalize the command for Windows
        normalized_cmd = []
        for part in cmd:
            if part.startswith("#!"):
                # Handle shebangs
                shebang = part[2:]
                if os.path.isfile(shebang):
                    normalized_cmd.append(shebang)
                else:
                    # If the shebang is not a valid file, keep it as is
                    normalized_cmd.append(part)
            else:
                # Normalize paths for Windows
                normalized_cmd.append(part.replace('/', '\\'))
        return tuple(normalized_cmd)
    return cmd

from functools import wraps

def mru_cache(maxsize=128, typed=False):
    """Decorator to wrap a function with a memoizing callable that saves
    up to `maxsize` results based on a Most Recently Used (MRU)
    algorithm."""

    cache = {}
    order = []

    @wraps(func)
    def wrapper(func):
        @wraps(func)
        def wrapped(*args, **kwargs):
            key = (args, frozenset(kwargs.items())) if typed else args
            if key in cache:
                order.remove(key)
                order.append(key)
                return cache[key]
            result = func(*args, **kwargs)
            if len(cache) >= maxsize:
                oldest = order.pop(0)
                del cache[oldest]
            cache[key] = result
            order.append(key)
            return result

        return wrapped

    return wrapper

def extostr(cls, e, max_level=30, max_path_level=5):
    import traceback

    def format_exception(exc, level, path_level):
        if level > max_level or path_level > max_path_level:
            return f"{exc.__class__.__name__}: {str(exc)}"

        tb = traceback.extract_tb(exc.__traceback__)
        formatted_tb = []
        for frame in tb:
            formatted_tb.append(f"File \"{frame.filename}\", line {frame.lineno}, in {frame.name}")

        return "\n".join(formatted_tb)

    exception_message = f"{e.__class__.__name__}: {str(e)}"
    formatted_traceback = format_exception(e, 0, 0)

    return f"{exception_message}\n{formatted_traceback}"

def minimalBases(classes):
    """
    Reduce a list of base classes to its ordered minimum equivalent
    """
    from collections import defaultdict

    class_graph = defaultdict(set)
    for cls in classes:
        for base in cls.__bases__:
            class_graph[base].add(cls)

    def find_minimal_bases(cls, visited):
        if cls in visited:
            return set()
        visited.add(cls)
        minimal_bases = {cls}
        for base in cls.__bases__:
            minimal_bases.update(find_minimal_bases(base, visited))
        return minimal_bases

    minimal_classes = set()
    visited = set()
    for cls in classes:
        minimal_classes.update(find_minimal_bases(cls, visited))

    return sorted(minimal_classes, key=lambda x: x.__name__)

