def verifyClass(iface, candidate, tentative=False):
    """
    Verify that the *candidate* might correctly provide *iface*.
    """
    if tentative:
        return issubclass(candidate, iface) or (hasattr(candidate, '__mro__') and iface in candidate.__mro__)
    return isinstance(candidate, iface)

def determineMetaclass(bases, explicit_mc=None):
    """
    Determine metaclass from 1+ bases and optional explicit __metaclass__
    """
    if explicit_mc is not None:
        return explicit_mc

    metaclasses = [type(base) for base in bases]
    if not metaclasses:
        return type

    metaclass = metaclasses[0]
    for mc in metaclasses[1:]:
        if not issubclass(mc, metaclass):
            metaclass = type('CombinedMeta', (metaclass, mc), {})

    return metaclass

def pop(self, key, default=__marker):
    """
    D.pop(k[,d]) -> v, remove specified key and return the corresponding value.
    If key is not found, d is returned if given, otherwise KeyError is raised.
    """
    if key in self:
        value = self[key]
        del self[key]
        return value
    elif default is not self.__marker:
        return default
    else:
        raise KeyError(key)

import random

class CustomDict:
    def __init__(self):
        self.data = {}

    def popitem(self):
        """
        Remove and return a random `(key, value)` pair.
        """
        if not self.data:
            raise KeyError("popitem(): dictionary is empty")
        key = random.choice(list(self.data.keys()))
        value = self.data.pop(key)
        return key, value

